const body = $json.body ?? {};
const firstBinaryKey = $binary ? Object.keys($binary)[0] : undefined;

let imageBase64 = (
  $json.image_base64 ??
  body.image_base64 ??
  $json.imageBase64 ??
  body.imageBase64 ??
  ''
).toString().trim();

if (!imageBase64 && firstBinaryKey) {
  const imageBuffer = await this.helpers.getBinaryDataBuffer(0, firstBinaryKey);
  imageBase64 = imageBuffer.toString('base64');
}

const prompt = (
  $json.chatInput ??
  body.chatInput ??
  body.prompt ??
  $json.prompt ??
  ''
).toString().trim();

const explicitMode = (
  $json.mode ??
  body.mode ??
  ''
).toString().toLowerCase().trim();

const mode = explicitMode || (imageBase64 ? 'describe' : 'generate');

return [{
  json: {
    prompt,
    mode,
    image_base64: imageBase64,
    ollama_host: (body.ollama_host ?? $json.ollama_host ?? 'http://ollama:11434').toString(),
    vision_model: (body.vision_model ?? $json.vision_model ?? 'llava:7b').toString(),
    image_gen_url: (body.image_gen_url ?? $json.image_gen_url ?? 'https://api.openai.com/v1/images/generations').toString(),
    image_gen_api_key: (body.image_gen_api_key ?? $json.image_gen_api_key ?? '').toString(),
    image_gen_model: (body.image_gen_model ?? $json.image_gen_model ?? 'gpt-image-1').toString(),
    image_size: (body.image_size ?? $json.image_size ?? '1024x1024').toString()
  }
}];

const req = $('Parse Request').first().json;

if (!req.prompt) {
  throw new Error('Missing prompt. Provide chatInput or prompt.');
}

if (!req.image_base64) {
  throw new Error('Describe mode requires image_base64 or an uploaded image binary file.');
}

const visionResponse = await this.helpers.httpRequest({
  method: 'POST',
  url: `${req.ollama_host}/api/chat`,
  headers: {
    'Content-Type': 'application/json'
  },
  body: {
    model: req.vision_model,
    stream: false,
    messages: [
      {
        role: 'user',
        content: req.prompt,
        images: [req.image_base64]
      }
    ]
  },
  json: true
});

const description = visionResponse?.message?.content || 'No description returned.';

return [{
  json: {
    mode: 'describe',
    provider: 'ollama',
    model: req.vision_model,
    output: description,
    text: description
  }
}];

const req = $('Parse Request').first().json;

if (!req.prompt) {
  throw new Error('Missing prompt. Provide chatInput or prompt.');
}

const headers = {
  'Content-Type': 'application/json'
};

if (req.image_gen_api_key) {
  headers.Authorization = `Bearer ${req.image_gen_api_key}`;
}

const generationResponse = await this.helpers.httpRequest({
  method: 'POST',
  url: req.image_gen_url,
  headers,
  body: {
    model: req.image_gen_model,
    prompt: req.prompt,
    size: req.image_size
  },
  json: true
});

const firstImage = generationResponse?.data?.[0] ?? {};
const imageUrl = firstImage.url ?? '';
const imageB64 = firstImage.b64_json ?? '';

let outputText = 'Image generated.';
if (imageUrl) {
  outputText = `Image generated: ${imageUrl}`;
} else if (imageB64) {
  outputText = 'Image generated successfully. b64_json returned in image_base64.';
}

return [{
  json: {
    mode: 'generate',
    provider: 'openai-compatible',
    model: req.image_gen_model,
    output: outputText,
    text: outputText,
    image_url: imageUrl,
    image_base64: imageB64
  }
}];

const data = $json;
const text = data.text || data.output || 'Done';

if (data.mode === 'generate' && data.image_base64) {
  return [{
    json: {
      ...data,
      text
    },
    binary: {
      generated_image: {
        data: data.image_base64,
        fileName: 'generated-image.png',
        mimeType: 'image/png'
      }
    }
  }];
}

return [{
  json: {
    ...data,
    text
  }
}];
